let companies = [];
let runMeta = { run_id: null, run_ts: null };
let dataSource = 'loading'; // 'loading' | 'live' | 'fallback'

function computeIndex(news, reddit, linkedin, github, hn, execHire, funding, patents) {
  const n = Math.min(news, CAPS.news) / CAPS.news;
  const r = Math.min(reddit, CAPS.reddit) / CAPS.reddit;
  const l = Math.min(linkedin, CAPS.linkedin) / CAPS.linkedin;
  const g = Math.min(github, CAPS.github) / CAPS.github;
  const h = Math.min(hn, CAPS.hn) / CAPS.hn;
  const e = Math.min(execHire, CAPS.exec_hire) / CAPS.exec_hire;
  const f = Math.min(funding, CAPS.funding) / CAPS.funding;
  const p = Math.min(patents, CAPS.patents) / CAPS.patents;
  return n * WEIGHTS.news + r * WEIGHTS.reddit + l * WEIGHTS.linkedin + g * WEIGHTS.github + h * WEIGHTS.hn
    + e * WEIGHTS.exec_hire + f * WEIGHTS.funding + p * WEIGHTS.patents;
}

function tierOf(idx) {
  if (idx >= 0.8) return 'Very Strong';
  if (idx >= 0.6) return 'Strong';
  if (idx >= 0.4) return 'Moderate';
  if (idx >= 0.2) return 'Weak';
  return 'Very Weak';
}

function tierClass(tier) {
  if (tier === 'Very Strong' || tier === 'Strong') return 'green';
  if (tier === 'Moderate') return 'amber';
  return 'rose';
}

function findCompany(name) {
  return companies.find((c) => c.company === name) || null;
}

/* One-sentence company blurbs — only for names we actually, verifiably
   know are real; every other company in this dataset is a discovery-
   pipeline placeholder/demo name, so they get an honest fallback rather
   than an invented-sounding description. Keyed by company_canonical. */
const COMPANY_BLURBS = {
  helsing: 'German defense-tech company building AI software for military and security applications.',
  allbirds: 'Footwear and apparel brand known for sustainable, natural materials like merino wool.',
  meta: 'Parent company of Facebook, Instagram, and WhatsApp, focused on social platforms and AI.',
  alibaba: 'Chinese e-commerce and cloud computing conglomerate operating Taobao, Tmall, and Alibaba Cloud.',
};
const NO_BLURB = 'No public description available.';

function getCompanyBlurb(c) {
  return COMPANY_BLURBS[c.company_canonical] || NO_BLURB;
}

/*
 * LinkedIn Jobs signal, by definition, only registers once a role is
 * already posted publicly — it's confirmation, not an early signal.
 * Every other source (funding news, community chatter, engineering
 * activity) can show up before a company starts hiring, so they're
 * grouped as "leading" — the earlier, more valuable signal for finding
 * opportunities before they become job postings.
 */
const SOURCE_TIMING = {
  news: 'leading', reddit: 'leading', github: 'leading', hn: 'leading',
  exec_hire: 'leading', funding: 'leading', patents: 'leading', linkedin: 'confirming',
};

function generateWhyItMatters(c) {
  const sources = [
    { key: 'news', label: 'News', value: c.news_signals },
    { key: 'reddit', label: 'Reddit', value: c.reddit_signals },
    { key: 'linkedin', label: 'LinkedIn', value: c.linkedin_signals },
    { key: 'github', label: 'GitHub', value: c.github_signals },
    { key: 'hn', label: 'Hacker News', value: c.hn_signals },
    { key: 'exec_hire', label: 'Executive Hires', value: c.exec_hire_signals },
    { key: 'funding', label: 'Funding', value: c.funding_signals },
    { key: 'patents', label: 'Patents', value: c.patent_signals },
  ];
  const top = sources.reduce((a, b) => (b.value > a.value ? b : a));
  const tierPhrase = c.tier.toLowerCase();
  const growthPhrase = c.tier === 'Very Strong' || c.tier === 'Strong'
    ? 'active headcount growth rather than a single one-off signal spike, making it a reasonable near-term target for outreach'
    : 'some hiring-adjacent activity, though the signal is not yet strong enough to be a confident outreach priority';
  const timingPhrase = SOURCE_TIMING[top.key] === 'leading'
    ? `That's a leading signal — it can show up before any role is publicly posted, so you may be finding this one early.`
    : `That's a confirming signal — LinkedIn activity like this usually means a role is already posted, so the opportunity is real but timing is less in your favor.`;
  return `<strong>${escapeXml(c.company)}</strong> is showing ${tierPhrase} combined signal this scan — driven primarily by ${top.label.toLowerCase()} activity (<span class="num">${top.value}</span> mentions) across news, community, and hiring channels. ${timingPhrase} That combination usually means ${growthPhrase}.`;
}

function hexToRgba(hex, alpha) {
  const n = parseInt(hex.replace('#', ''), 16);
  const r = (n >> 16) & 255, g = (n >> 8) & 255, b = n & 255;
  return `rgba(${r}, ${g}, ${b}, ${alpha})`;
}

function escapeXml(str) {
  return String(str).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

/* ── Live data loading ──────────────────────────────────────────────── */

/* Minimal CSV parser — handles quoted fields (embedded commas, escaped
   quotes) since company names could contain either. */
function parseCSV(text) {
  const rows = [];
  let row = [], field = '', inQuotes = false;
  for (let i = 0; i < text.length; i++) {
    const ch = text[i];
    if (inQuotes) {
      if (ch === '"') {
        if (text[i + 1] === '"') { field += '"'; i++; }
        else inQuotes = false;
      } else {
        field += ch;
      }
    } else if (ch === '"') {
      inQuotes = true;
    } else if (ch === ',') {
      row.push(field);
      field = '';
    } else if (ch === '\n' || ch === '\r') {
      if (ch === '\r' && text[i + 1] === '\n') i++;
      row.push(field);
      field = '';
      if (row.length > 1 || row[0] !== '') rows.push(row);
      row = [];
    } else {
      field += ch;
    }
  }
  if (field !== '' || row.length) { row.push(field); rows.push(row); }
  if (!rows.length) return [];

  const header = rows[0].map((h) => h.trim());
  return rows.slice(1)
    .filter((r) => r.length === header.length)
    .map((r) => {
      const obj = {};
      header.forEach((h, idx) => { obj[h] = r[idx]; });
      return obj;
    });
}

/* Rejects malformed rows — e.g. the discovery LLM has, at least once,
   extracted an entire sentence as a "company name" instead of an actual
   name. Real company names are short; anything wildly long is discarded
   rather than shown as a fake company. */
function isValidCompanyRow(row) {
  if (!row.company_canonical || !row.company_display) return false;
  if (row.company_display.length > 60) return false;
  if (!row.run_id || !row.run_ts) return false;
  return true;
}

/* The discovery LLM occasionally names the same real signal differently
   across runs (e.g. "Unspecified AI startup by former Target executive"
   vs "AI startup launched by former Target executive" — same near-
   identical signal values, different extracted name), which would
   otherwise show up as two separate companies. Manually alias any
   known duplicate canonical key onto the one we keep, applied here so
   it merges correctly regardless of whether the row came from the live
   sheet or FALLBACK_ROWS. */
const CANONICAL_ALIASES = {
  unspecifiedstartupbyformertargetexecutive: 'startuplaunchedbyformertargetexecutive',
  startupbyformerallbirdsceo: 'allbirdsstartup',
  alibabagroup: 'alibaba',
};

/* Groups raw CSV rows by company, computing the current (latest-run)
   snapshot per company plus its full real history (every past run) for
   genuine trend charts — no synthetic/illustrative data involved. */
function buildCompaniesFromRows(rows) {
  const grouped = {};
  rows.forEach((row) => {
    const key = CANONICAL_ALIASES[row.company_canonical] || row.company_canonical;
    if (!grouped[key]) grouped[key] = [];
    grouped[key].push(row);
  });

  let latestRunTs = null, latestRunId = null;

  const built = Object.entries(grouped).map(([canonicalKey, runs]) => {
    runs.sort((a, b) => new Date(a.run_ts) - new Date(b.run_ts));

    const history = runs.map((r) => {
      const index = computeIndex(
        Number(r.news_signals) || 0,
        Number(r.reddit_signals) || 0,
        Number(r.linkedin_signals) || 0,
        Number(r.github_signals) || 0,
        Number(r.hn_signals) || 0,
        Number(r.exec_hire_signals) || 0,
        Number(r.funding_signals) || 0,
        Number(r.patent_signals) || 0
      );
      return { run_id: r.run_id, run_ts: r.run_ts, index };
    });

    const latest = runs[runs.length - 1];
    const news = Number(latest.news_signals) || 0;
    const reddit = Number(latest.reddit_signals) || 0;
    const linkedin = Number(latest.linkedin_signals) || 0;
    const github = Number(latest.github_signals) || 0;
    const hn = Number(latest.hn_signals) || 0;
    const execHire = Number(latest.exec_hire_signals) || 0;
    const funding = Number(latest.funding_signals) || 0;
    const patents = Number(latest.patent_signals) || 0;
    const index = computeIndex(news, reddit, linkedin, github, hn, execHire, funding, patents);

    /* company_url is a recent, sparsely-populated addition — most rows
       (including possibly the latest run) don't have it yet. Scan
       backward through this company's own history for the most recent
       run that DOES, rather than assuming the latest run has it. */
    let companyUrl = '';
    for (let i = runs.length - 1; i >= 0; i--) {
      if (runs[i].company_url && runs[i].company_url.trim()) { companyUrl = runs[i].company_url.trim(); break; }
    }

    if (!latestRunTs || new Date(latest.run_ts) > new Date(latestRunTs)) {
      latestRunTs = latest.run_ts;
      latestRunId = latest.run_id;
    }

    return {
      company: latest.company_display,
      company_canonical: canonicalKey,
      news_signals: news,
      reddit_signals: reddit,
      linkedin_signals: linkedin,
      github_signals: github,
      hn_signals: hn,
      exec_hire_signals: execHire,
      funding_signals: funding,
      patent_signals: patents,
      discovery_source: latest.discovery_source || 'tracked',
      company_url: companyUrl,
      opportunity_index: Math.round(index * 100) / 100,
      opportunity_index_precise: index,
      tier: tierOf(index),
      history,
    };
  });

  return { companies: built, runMeta: { run_id: latestRunId, run_ts: latestRunTs } };
}

/* Fetches the live published sheet; falls back to the last-known-good
   snapshot if the fetch fails or returns nothing usable. Always
   resolves (never rejects) so callers don't need their own fallback. */
function loadCompanyData() {
  return fetch(CSV_URL)
    .then((res) => {
      if (!res.ok) throw new Error(`Fetch failed: ${res.status}`);
      return res.text();
    })
    .then((text) => {
      const rows = parseCSV(text).filter(isValidCompanyRow);
      if (!rows.length) throw new Error('No valid rows in live data');
      const built = buildCompaniesFromRows(rows);
      companies = built.companies;
      runMeta = built.runMeta;
      dataSource = 'live';
      return companies;
    })
    .catch((err) => {
      console.warn('Live data fetch failed, using fallback snapshot:', err);
      const rows = FALLBACK_ROWS.filter(isValidCompanyRow);
      const built = buildCompaniesFromRows(rows);
      companies = built.companies;
      runMeta = built.runMeta;
      dataSource = 'fallback';
      return companies;
    });
}

/* Real per-company contacts, keyed by canonical company key (same
   CANONICAL_ALIASES resolution as the main data, so a contact found
   under a since-merged duplicate name still joins correctly). This is
   supplementary, not core — a failed live fetch falls back to the
   last-known-good CONTACTS snapshot below, same pattern as
   FALLBACK_ROWS for the main data. */
let CONTACTS = {};

/* Some companies turn up more than one candidate contact in a single
   pull (the search isn't a 1:1 match) — keep whichever one the sheet
   lists first rather than letting a later, potentially worse match
   silently overwrite it. */
/* Maps each company to an ARRAY of candidate contacts, not just one —
   the search now routinely returns several people per company, several
   of them false positives (surname coincidences), so the UI shows the
   list and lets a human pick rather than the app silently guessing
   which one is right. Deduped by name (case-insensitive) since the
   same real person often appears more than once across search passes. */
function buildContactsMap(rows) {
  const map = {};
  const seenNames = {};
  rows.forEach((r) => {
    if (!r.company_canonical || !r.contact_name || !r.linkedin_url) return;
    const key = CANONICAL_ALIASES[r.company_canonical] || r.company_canonical;
    const nameKey = key + '::' + r.contact_name.trim().toLowerCase();
    if (seenNames[nameKey]) return;
    seenNames[nameKey] = true;
    if (!map[key]) map[key] = [];
    map[key].push(r);
  });
  return map;
}

